pub fn setText(id: u8, text: []const u8) void {
    if (id >= MAX_INPUTS) {
        return;
    }
    var inp = &inputs[id];
    const prev_len = inp.len;
    const copy_len: u16 = @intCast(@min(text.len, BUF_SIZE - 1));
